final class IdentityMatMulStart implements VortexStart { private static final Logger LOG = Logger . getLogger ( IdentityMatMulStart . class . getName ( ) ) ; private final int divideFactor ; private final int numRows ; private final int numColumns ; @ Inject private IdentityMatMulStart ( @ Parameter ( MatMul . DivideFactor . class ) final int divideFactor , @ Parameter ( MatMul . NumRows . class ) final int numRows , @ Parameter ( MatMul . NumColumns . class ) final int numColumns ) { this . divideFactor = divideFactor ; this . numRows = numRows ; this . numColumns = numColumns ; } @ Override public void start ( final VortexThreadPool vortexThreadPool ) { final List < Matrix < Double > > leftSplits = generateMatrixSplits ( numRows , numColumns , divideFactor ) ; final Matrix < Double > right = generateIdentityMatrix ( numColumns ) ; final double start = System . currentTimeMillis ( ) ; final CountDownLatch latch = new CountDownLatch ( divideFactor ) ; final FutureCallback < MatMulOutput > callback = new FutureCallback < MatMulOutput > ( ) { @ Override public void onSuccess ( final MatMulOutput output ) { final int index = output . getIndex ( ) ; final Matrix < Double > result = output . getResult ( ) ; if ( result . equals ( leftSplits . get ( index ) ) ) { latch . countDown ( ) ; } else { throw new RuntimeException ( index + " th result is not correct." ) ; } } @ Override public void onFailure ( final Throwable t ) { throw new RuntimeException ( t ) ; } } ; final MatMulFunction matMulFunction = new MatMulFunction ( ) ; for ( int i = 0 ; i < divideFactor ; i ++ ) { vortexThreadPool . submit ( matMulFunction , new MatMulInput ( i , leftSplits . get ( i ) , right ) , callback ) ; } try { latch . await ( ) ; LOG . log ( Level . INFO , "Job Finish Time: " + ( System . currentTimeMillis ( ) - start ) ) ; } catch ( final InterruptedException e ) { throw new RuntimeException ( e ) ; } } private Matrix < Double > generateRandomMatrix ( final int nRows , final int nColumns ) { final List < List < Double > > rows = new ArrayList < > ( nRows ) ; final Random random = new Random ( ) ; for ( int i = 0 ; i < nRows ; i ++ ) { final List < Double > row = new ArrayList < > ( nColumns ) ; for ( int j = 0 ; j < nColumns ; j ++ ) { row . add ( random . nextDouble ( ) ) ; } rows . add ( row ) ; } return new RowMatrix ( rows ) ; } private Matrix < Double > generateIdentityMatrix ( final int numDimension ) { final List < List < Double > > rows = new ArrayList < > ( numDimension ) ; for ( int i = 0 ; i < numDimension ; i ++ ) { final List < Double > row = new ArrayList < > ( numDimension ) ; for ( int j = 0 ; j < numDimension ; j ++ ) { final double value = i == j ? 1 : 0 ; row . add ( value ) ; } rows . add ( row ) ; } return new RowMatrix ( rows ) ; } private List < Matrix < Double > > generateMatrixSplits ( final int nRows , final int nColumns , final int nSplits ) { final List < Matrix < Double > > splits = new ArrayList < > ( nSplits ) ; int remainingNumSplits = nSplits ; int remainingNumRows = nRows ; for ( int i = 0 ; i < nSplits ; i ++ ) { final int splitNumRows = ( remainingNumRows + remainingNumSplits - 1 ) / remainingNumSplits ; splits . add ( generateRandomMatrix ( splitNumRows , nColumns ) ) ; remainingNumRows -= splitNumRows ; remainingNumSplits -- ; } return splits ; } }